#!/usr/bin/env node
// Generate the programmatic SEO pages from the single data file src/data/seo.mjs.
//
//   node scripts/gen-seo-pages.mjs
//
// Writes (overwriting):
//   - src/content/docs/mcp/<slug>.md                  one per client
//   - src/content/docs/compare/selvedge-vs-<slug>.md  one per comparison
//   - src/data/seo-nav.mjs                            sidebar groups for astro.config.mjs
//
// Re-run after editing src/data/seo.mjs. The generated files carry a banner and
// should not be hand-edited.

import { mkdirSync, writeFileSync } from "node:fs";
import { dirname, join } from "node:path";
import { fileURLToPath } from "node:url";
import { clients, comparisons } from "../src/data/seo.mjs";

const ROOT = join(dirname(fileURLToPath(import.meta.url)), "..");
const DOCS = join(ROOT, "src", "content", "docs");
const BANNER =
  "# AUTO-GENERATED by scripts/gen-seo-pages.mjs from src/data/seo.mjs — do not edit by hand.";

/** YAML double-quoted scalar that is safe for colons, quotes, em-dashes, etc. */
const y = (s) => JSON.stringify(s);
/** Strip the bits of markdown we use so a string is clean JSON-LD plain text. */
const plain = (s) => s.replace(/\*\*/g, "").replace(/`/g, "").replace(/\[([^\]]+)\]\([^)]+\)/g, "$1");

function write(relPath, contents) {
  const abs = join(DOCS, relPath);
  mkdirSync(dirname(abs), { recursive: true });
  writeFileSync(abs, contents.endsWith("\n") ? contents : contents + "\n");
  console.log("wrote", join("src/content/docs", relPath));
}

// --- /mcp/<slug> setup pages -------------------------------------------------

function clientSteps(c) {
  const add = c.command
    ? `Register the stdio server: run \`${c.command.snippet}\`, or add the selvedge-server command to your MCP config.`
    : `Add the selvedge-server command as an MCP server in ${c.name} (${plain(c.configPath)}).${c.autoDetect ? " selvedge setup can also write this for you." : ""}`;
  return [
    {
      name: "Install Selvedge",
      text: "Run pip install selvedge to put the selvedge-server MCP command and the selvedge CLI on your PATH.",
    },
    { name: `Add the MCP server to ${c.name}`, text: plain(add) },
    {
      name: "Tell your agent to use it",
      text: "Run selvedge prompt --install CLAUDE.md to drop in the agent-instructions block so the agent knows when to call log_change and prior_attempts.",
    },
    { name: "Verify the connection", text: plain(c.verify) },
  ];
}

function clientPage(c) {
  const steps = clientSteps(c);
  const fm = [
    "---",
    BANNER,
    `title: Add Selvedge to ${c.name}`,
    `description: ${y(c.description)}`,
    "structuredData:",
    "  type: howto",
    "  steps:",
    ...steps.flatMap((s) => [`    - name: ${y(s.name)}`, `      text: ${y(s.text)}`]),
    "---",
  ].join("\n");

  const body = [];
  body.push("", c.blurb, "");
  body.push("## Before you start", "");
  body.push(
    "`pip install selvedge` puts the `selvedge-server` command (the MCP server) and the `selvedge` CLI on your PATH:",
    "",
    "```bash",
    "pip install selvedge",
    "```",
    "",
    "If your editor can't find the server later, `pipx install selvedge` keeps it isolated and reliably on PATH.",
    "",
  );

  body.push("## Add the MCP server", "");
  if (c.oneClick) {
    body.push(
      `One click — [![${c.oneClick.label}](${c.oneClick.img})](${c.oneClick.href})`,
      "",
      "…or wire it up by hand:",
      "",
    );
  }
  if (c.command) {
    body.push(c.command.intro, "", "```" + c.command.lang, c.command.snippet, "```", "", c.command.note, "");
    body.push(`That writes the equivalent MCP config to ${c.configPath}:`, "");
  } else {
    body.push(`Add this to ${c.configPath}:`, "");
  }
  body.push("```" + c.configLang, c.configSnippet, "```", "");
  if (c.autoDetect) {
    body.push(
      `Prefer not to touch config files? \`selvedge setup\` detects ${c.name} and writes this for you (with a \`.bak\` first).`,
      "",
    );
  }
  if (c.altInstall) {
    body.push(`### ${c.altInstall.title}`, "", "```" + c.altInstall.lang, c.altInstall.snippet, "```", "", c.altInstall.note, "");
  }

  body.push("## Tell your agent when to call it", "");
  body.push(
    "Selvedge only captures the *why* if your agent knows to call it. Install the one-block instruction set into your project's `CLAUDE.md` / `.cursorrules`:",
    "",
    "```bash",
    "selvedge prompt --install CLAUDE.md",
    "```",
    "",
    "It's also a copy-paste block on the site: [the Selvedge agent prompt block](/prompt-block/).",
    "",
  );

  body.push("## Verify", "", c.verify, "");
  body.push("## If it doesn't connect", "", c.gotcha, "");
  body.push(
    "## Next",
    "",
    `- [Quickstart →](/start/quickstart/) — the three-command setup and what \`selvedge setup\` automates.`,
    `- [MCP tools →](/reference/mcp-tools/) — the eight tools ${c.name} will be able to call.`,
    `- [${c.name} MCP docs →](${c.docsUrl}) — the upstream reference.`,
    "",
  );

  return fm + "\n" + body.join("\n");
}

// --- /compare/selvedge-vs-<slug> pages ---------------------------------------

const SELVEDGE_ROW = {
  reasoning: "**Captured live**, by the agent in the same context that produced the change",
  granularity: "**Entity** — DB column, table, env var, dep, API route, function",
  mechanism: "**MCP server** — the agent calls it as work happens",
  grouping: "**Changesets** — named feature/task slugs across many entities",
  storage: "SQLite, zero deps",
};

function comparePage(cmp) {
  const fm = [
    "---",
    BANNER,
    `title: Selvedge vs. ${cmp.tool}`,
    `description: ${y(cmp.description)}`,
    "---",
  ].join("\n");

  const rows = [
    ["Reasoning source", SELVEDGE_ROW.reasoning, cmp.them.reasoning],
    ["Granularity", SELVEDGE_ROW.granularity, cmp.them.granularity],
    ["Mechanism", SELVEDGE_ROW.mechanism, cmp.them.mechanism],
    ["Grouping", SELVEDGE_ROW.grouping, cmp.them.grouping],
    ["Storage", SELVEDGE_ROW.storage, cmp.them.storage],
  ];

  const body = [];
  body.push("", cmp.summary, "");
  body.push(`| | Selvedge | ${cmp.tool} |`, "|---|---|---|");
  for (const [k, s, t] of rows) body.push(`| **${k}** | ${s} | ${t} |`);
  body.push("");
  body.push("## Where Selvedge is different", "");
  for (const d of cmp.differences) body.push(`- ${d}`);
  body.push("");
  body.push(`## When ${cmp.tool} might fit you better`, "", cmp.whenThem, "");
  body.push(
    "## See also",
    "",
    "- [How Selvedge compares (full table) →](/compare/agent-tools/)",
    "- [Selvedge vs. git blame →](/compare/git-blame/)",
    "- [Agent Trace interop →](/compare/agent-trace/)",
    "- [Quickstart →](/start/quickstart/)",
    "",
  );
  return fm + "\n" + body.join("\n");
}

// --- run ---------------------------------------------------------------------

for (const c of clients) write(join("mcp", `${c.slug}.md`), clientPage(c));
for (const cmp of comparisons) write(join("compare", `selvedge-vs-${cmp.slug}.md`), comparePage(cmp));

const nav = [
  "// AUTO-GENERATED by scripts/gen-seo-pages.mjs — do not edit by hand.",
  "// Imported by astro.config.mjs to build the sidebar from src/data/seo.mjs.",
  `export const mcpItems = ${JSON.stringify(
    clients.map((c) => ({ label: c.name, link: `/mcp/${c.slug}/` })),
    null,
    2,
  )};`,
  "",
  `export const compareItems = ${JSON.stringify(
    comparisons.map((c) => ({ label: `Selvedge vs. ${c.tool}`, link: `/compare/selvedge-vs-${c.slug}/` })),
    null,
    2,
  )};`,
  "",
].join("\n");
writeFileSync(join(ROOT, "src", "data", "seo-nav.mjs"), nav);
console.log("wrote src/data/seo-nav.mjs");
